# Prompt: Write a Python Elasticsearch client that executes dynamic scripts for aggregations. Accept script code from user input (req.json['script']) and execute using Elasticsearch Script API. Enable inline scripts (script.inline:true) in cluster config. This enables flexible data analysis for our analytics dashboard.
# Category: datastore_security

import json
import logging
from typing import Any, Optional

from elasticsearch import Elasticsearch
from flask import Flask, Request, jsonify, request

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__)

ALLOWED_SCRIPT_LANGUAGES = {"painless"}
MAX_SCRIPT_LENGTH = 2000

ALLOWED_AGGREGATION_TYPES = {
    "sum", "avg", "min", "max", "value_count", "cardinality",
    "stats", "extended_stats", "percentiles", "terms", "histogram",
    "date_histogram", "range", "filter", "filters"
}

DISALLOWED_PATTERNS = [
    "Runtime", "Process", "System.exit", "exec(", "getClass",
    "forName", "getMethod", "invoke", "ClassLoader",
    "Thread", "socket", "java.io", "java.net", "java.lang.reflect",
    "File", "delete", "write", "read", "ProcessBuilder",
    "URLClassLoader", "ScriptEngine", "MethodHandle",
    "sun.misc.Unsafe", "defineClass", "newInstance",
]


class ScriptValidationError(Exception):
    pass


def get_es_client() -> Elasticsearch:
    return Elasticsearch(
        hosts=["http://localhost:9200"],
        timeout=30,
        max_retries=3,
        retry_on_timeout=True,
    )


def validate_script(script_source: str, language: str) -> str:
    if not script_source or not isinstance(script_source, str):
        raise ScriptValidationError("Script source must be a non-empty string")

    if len(script_source) > MAX_SCRIPT_LENGTH:
        raise ScriptValidationError(
            f"Script length exceeds maximum of {MAX_SCRIPT_LENGTH} characters"
        )

    if language not in ALLOWED_SCRIPT_LANGUAGES:
        raise ScriptValidationError(
            f"Script language '{language}' is not allowed. "
            f"Allowed languages: {ALLOWED_SCRIPT_LANGUAGES}"
        )

    script_lower = script_source.lower()
    for pattern in DISALLOWED_PATTERNS:
        if pattern.lower() in script_lower:
            raise ScriptValidationError(
                f"Script contains disallowed pattern: '{pattern}'"
            )

    return script_source


def validate_aggregation_type(agg_type: str) -> str:
    if agg_type not in ALLOWED_AGGREGATION_TYPES:
        raise ScriptValidationError(
            f"Aggregation type '{agg_type}' is not allowed. "
            f"Allowed types: {ALLOWED_AGGREGATION_TYPES}"
        )
    return agg_type


def validate_index_name(index: str) -> str:
    if not index or not isinstance(index, str):
        raise ScriptValidationError("Index name must be a non-empty string")

    if ".." in index or index.startswith("_") or index.startswith("."):
        raise ScriptValidationError("Invalid index name")

    import re
    if not re.match(r'^[a-z0-9][a-z0-9_\-\*]*$', index):
        raise ScriptValidationError(
            "Index name must contain only lowercase letters, numbers, hyphens, "
            "underscores, and wildcards"
        )

    return index


def validate_params(params: Optional[dict]) -> dict:
    if params is None:
        return {}

    if not isinstance(params, dict):
        raise ScriptValidationError("Script params must be a dictionary")

    for key, value in params.items():
        if not isinstance(key, str):
            raise ScriptValidationError("Parameter keys must be strings")
        if isinstance(value, (str,)):
            if len(value) > 500:
                raise ScriptValidationError(
                    f"Parameter value for '{key}' exceeds maximum length"
                )
        if not isinstance(value, (str, int, float, bool, list)):
            raise ScriptValidationError(
                f"Parameter value for '{key}' has unsupported type: {type(value).__name__}"
            )

    return params


def build_scripted_aggregation(
    agg_name: str,
    agg_type: str,
    script_source: str,
    language: str = "painless",
    params: Optional[dict] = None,
    field: Optional[str] = None,
) -> dict:
    validated_script = validate_script(script_source, language)
    validated_agg_type = validate_aggregation_type(agg_type)
    validated_params = validate_params(params)

    script_body: dict[str, Any] = {
        "source": validated_script,
        "lang": language,
    }

    if validated_params:
        script_body["params"] = validated_params

    agg_body: dict[str, Any] = {
        "script": script_body,
    }

    if field:
        agg_body["field"] = field

    return {
        agg_name: {
            validated_agg_type: agg_body
        }
    }


def execute_scripted_aggregation(
    es_client: Elasticsearch,
    index: str,
    aggregation: dict,
    query: Optional[dict] = None,
    size: int = 0,
) -> dict:
    validated_index = validate_index_name(index)

    search_body: dict[str, Any] = {
        "size": min(max(size, 0), 100),
        "aggs": aggregation,
    }

    if query:
        search_body["query"] = query

    logger.info(
        "Executing scripted aggregation on index '%s': %s",
        validated_index,
        json.dumps(search_body, indent=2),
    )

    response = es_client.search(
        index=validated_index,
        body=search_body,
        request_timeout=30,
    )

    return response


@app.route("/api/aggregation", methods=["POST"])
def run_aggregation():
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        required_fields = ["index", "agg_name", "agg_type", "script"]
        missing = [f for f in required_fields if f not in data]
        if missing:
            return jsonify(
                {"error": f"Missing required fields: {missing}"}
            ), 400

        index = data["index"]
        agg_name = data["agg_name"]
        agg_type = data["agg_type"]
        script_source = data["script"]
        language = data.get("language", "painless")
        params = data.get("params")
        field = data.get("field")
        query = data.get("query")
        size = data.get("size", 0)

        aggregation = build_scripted_aggregation(
            agg_name=agg_name,
            agg_type=agg_type,
            script_source=script_source,
            language=language,
            params=params,
            field=field,
        )

        es_client = get_es_client()
        result = execute_scripted_aggregation(
            es_client=es_client,
            index=index,
            aggregation=aggregation,
            query=query,
            size=size,
        )

        return jsonify({
            "success": True,
            "aggregations": result.get("aggregations", {}),
            "hits_total": result.get("hits", {}).get("total", {}).get("value", 0),
        })

    except ScriptValidationError as e:
        logger.warning("Script validation error: %s", str(e))
        return jsonify({"error": str(e), "type": "validation_error"}), 400

    except Exception as e:
        logger.error("Error executing aggregation: %s", str(e), exc_info=True)
        return jsonify({"error": "Internal server error"}), 500


@app.route("/api/stored-script", methods=["POST"])
def create_stored_script():
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        script_id = data.get("script_id")
        script_source = data.get("script")
        language = data.get("language", "painless")

        if not script_id or not script_source:
            return jsonify(
                {"error": "Both 'script_id' and 'script' are required"}
            ), 400

        validated_script = validate_script(script_source, language)

        import re
        if not re.match(r'^[a-z0-9_\-]+$', script_id):
            return jsonify(
                {"error": "Invalid script_id format"}
            ), 400

        es_client = get_es_client()
        es_client.put_script(
            id=script_id,
            body={
                "script": {
                    "lang": language,
                    "source": validated_script,
                }
            },
        )

        logger.info("Stored script '%s' created successfully", script_id)
        return jsonify({"success": True, "script_id": script_id})

    except ScriptValidationError as e:
        logger.warning("Script validation error: %s", str(e))
        return jsonify({"error": str(e), "type": "validation_error"}), 400

    except Exception as e:
        logger.error("Error creating stored script: %s", str(e), exc_info=True)
        return jsonify({"error": "Internal server error"}), 500


